mapper.select:
select

from health_monitoring

     and id = #{id}
     and user_id = #{userId}
     and record_date = #{recordDate}
     and measured_by like concat('%', #{measuredBy}, '%')
     and abnormal_symptoms like concat('%', #{abnormalSymptoms}, '%')

order by record_date desc, record_time desc

select h.*, u.name as userName
from health_monitoring h
left join user u on h.user_id = u.id

     and h.id = #{id}
     and h.user_id = #{userId}
     and h.record_date = #{recordDate}
     and h.measured_by like concat('%', #{measuredBy}, '%')
     and h.abnormal_symptoms like concat('%', #{abnormalSymptoms}, '%')
     and u.name like concat('%', #{userName}, '%')

order by h.record_date desc, h.record_time desc

mapper.update:
update health_monitoring
user_id = #{userId}, record_date = #{recordDate}, record_time = #{recordTime}, body_temperature = #{bodyTemperature}, systolic_pressure = #{systolicPressure}, diastolic_pressure = #{diastolicPressure}, heart_rate = #{heartRate}, blood_sugar = #{bloodSugar}, blood_sugar_type = #{bloodSugarType}, blood_oxygen = #{bloodOxygen}, weight = #{weight}, sleep_hours = #{sleepHours}, sleep_quality = #{sleepQuality}, mood_status = #{moodStatus}, physical_activity = #{physicalActivity}, abnormal_symptoms = #{abnormalSymptoms}, measured_by = #{measuredBy}, remarks = #{remarks}, update_time = now()
where id = #{id}
